import{_ as c,C as i,o as h,c as m,j as a,a as o,E as t,a3 as u}from"./chunks/framework.gsMzR_Kb.js";const D=JSON.parse('{"title":"道德经第一章","description":"从道、名、无、有、玄进入《道德经》的总门。","frontmatter":{"title":"道德经第一章","description":"从道、名、无、有、玄进入《道德经》的总门。","category":"guide","aliases":["道德经第一章","老子第一章","道可道","dao de jing chapter 1"],"source":["通行本《道德经》","王弼注本系统"]},"headers":[],"relativePath":"daoism/texts/dao-de-jing/chapter-01.md","filePath":"daoism/texts/dao-de-jing/chapter-01.md","lastUpdated":1777132262000}'),g={name:"daoism/texts/dao-de-jing/chapter-01.md"};function x(b,e,_,P,f,k){const l=i("DaoReadingPrelude"),n=i("DaoOriginalReading"),r=i("DaoLineGuide"),d=i("DaoPinyinGlossary"),p=i("DaoParallelReading"),s=i("DaoKeywordCards");return h(),m("div",null,[e[0]||(e[0]=a("h1",{id:"道德经第一章",tabindex:"-1"},[o("道德经第一章 "),a("a",{class:"header-anchor",href:"#道德经第一章","aria-label":'Permalink to "道德经第一章"'},"​")],-1)),t(l,{title:"先看道与名如何开门",summary:"这一章不是急着定义“道”，而是先提醒读者：语言能引路，但不能替代源头本身。最适合的进入方式，是先读原文的气息，再看断句与关键词如何慢慢展开。",points:[{label:"先读",text:"让句子先完整落下来，不急着拆。"},{label:"再辨",text:"看无 / 有、妙 / 徼如何相对出现。"},{label:"后解",text:"最后再回到名与道的关系。"}],hint:"若是第一次读《道德经》，建议先把本章读两遍，再进入下面的逐句引读与关键词卡片。"}),e[1]||(e[1]=a("h2",{id:"【原典层】原文",tabindex:"-1"},[o("【原典层】原文 "),a("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),t(n,{paragraphs:["道可道，非常道。","名可名，非常名。","无名天地之始；","有名万物之母。","故常无欲，以观其妙；","常有欲，以观其徼。","此两者，同出而异名，同谓之玄。","玄之又玄，众妙之门。"]}),t(r,{lines:[{text:"道可道，非常道。名可名，非常名。",tone:"先拆执著",guide:"先不要急着把“道”解释死，老子先做的，是把语言的把握感轻轻卸下来。"},{text:"无名天地之始；有名万物之母。",tone:"源与流",guide:"一句看源头，一句看展开；不是对立，而是两个层次。"},{text:"故常无欲，以观其妙；常有欲，以观其徼。此两者，同出而异名，同谓之玄。玄之又玄，众妙之门。",tone:"观法转深",guide:"不同心态看到不同层面，最后又被收回同一源头。",note:"读这一段时，节奏宜放缓，尤其“同出而异名”与“玄之又玄”两句。"}]}),e[2]||(e[2]=a("h2",{id:"【原典层】注音-生僻字",tabindex:"-1"},[o("【原典层】注音 / 生僻字 "),a("a",{class:"header-anchor",href:"#【原典层】注音-生僻字","aria-label":'Permalink to "【原典层】注音 / 生僻字"'},"​")],-1)),t(d,{description:"这一章字不多，但“徼”与“玄”是理解路径的关键节点。",items:[{char:"徼",pinyin:"jiào",tag:"关键字",note:"边际、外缘、轮廓；此处偏向“可见之迹”。"},{char:"玄",pinyin:"xuán",tag:"核心字",note:"深、幽、难以一言穷尽；不是故作神秘，而是指向未可尽说之深处。"}]}),e[3]||(e[3]=a("h2",{id:"【原典层】断句",tabindex:"-1"},[o("【原典层】断句 "),a("a",{class:"header-anchor",href:"#【原典层】断句","aria-label":'Permalink to "【原典层】断句"'},"​")],-1)),t(p,{sections:[{label:"道与名",original:"道可道，非常道。名可名，非常名。",reading:"道 / 可道 / 非常道。名 / 可名 / 非常名。",translation:"凡能被完全说出来的“道”，都不是终极之道；凡能被完全固定下来的“名”，也不是终极之名。",note:"第一组句子适合读得短促一点，形成“说得出 / 说不尽”的张力。"},{label:"无与有",original:"无名天地之始；有名万物之母。",reading:"无名 / 天地之始；有名 / 万物之母。",translation:"未落入名称时，更接近天地初始；进入命名之后，万物开始展开成可识别的世界。"},{label:"妙与徼",original:"故常无欲，以观其妙；常有欲，以观其徼。此两者，同出而异名，同谓之玄。玄之又玄，众妙之门。",reading:"故常无欲 / 以观其妙；常有欲 / 以观其徼。此两者 / 同出而异名，同谓之玄。玄之又玄，众妙之门。",translation:"不同的观看方式，会看到源头的幽微之妙，或已显之迹；它们虽名相不同，终究同出一源。",note:"这一组适合边读边看白话引读，能更明显感到“同出一源”的收束。"}]}),e[4]||(e[4]=a("h2",{id:"【原典层】关键词",tabindex:"-1"},[o("【原典层】关键词 "),a("a",{class:"header-anchor",href:"#【原典层】关键词","aria-label":'Permalink to "【原典层】关键词"'},"​")],-1)),t(s,{items:[{term:"道",meaning:"根本之理、运行之则，也是无法被固定语言完全包住的所指。",context:"本章先不是定义道，而是先提醒“道不可被说尽”。"},{term:"名",meaning:"命名、概念、标签、分别世界的方式。",context:"一旦进入“名”，世界就开始被分门别类。"},{term:"无",meaning:"未分、未定、尚未落入概念分别。",context:"更接近“天地之始”的源头感。"},{term:"有",meaning:"已显、已分、可识、可名。",context:"更接近万物展开之后的世界。"},{term:"妙",meaning:"幽微、深处、未显之妙。",context:"常无欲，才更容易见到这一层。"},{term:"徼",pinyin:"jiào",meaning:"边际、外缘、轮廓、可见之迹。",context:"常有欲，更容易看到显出来的边界与端倪。"},{term:"玄",pinyin:"xuán",meaning:"深、幽、难以一言穷尽。",context:"不是神秘化，而是指出源头问题无法被一句话封住。"}]}),e[5]||(e[5]=u('<h2 id="【解读层】三问解读" tabindex="-1">【解读层】三问解读 <a class="header-anchor" href="#【解读层】三问解读" aria-label="Permalink to &quot;【解读层】三问解读&quot;">​</a></h2><h3 id="象-这一章在说什么" tabindex="-1">象：这一章在说什么 <a class="header-anchor" href="#象-这一章在说什么" aria-label="Permalink to &quot;象：这一章在说什么&quot;">​</a></h3><p>第一章像是在给整部《道德经》立门规。</p><p>它先提醒读者：</p><ul><li>凡是可以被完全说出来的“道”，都不是终极的道</li><li>凡是可以被完全固定下来的“名”，都不是终极的名</li></ul><p>接着，它又把“无名”与“有名”展开为两种层次：</p><ul><li><code>无名</code> 更接近源头</li><li><code>有名</code> 更接近万物的展开</li></ul><p>再进一步，它指出“无欲”与“有欲”会带来不同的观看结果：</p><ul><li><code>无欲</code> 更容易见其妙</li><li><code>有欲</code> 更容易见其徼</li></ul><p>最后，它把这些看似不同的两端重新收回到一个更深的层次：同出而异名，同谓之玄。</p><h3 id="理-为什么这样说" tabindex="-1">理：为什么这样说 <a class="header-anchor" href="#理-为什么这样说" aria-label="Permalink to &quot;理：为什么这样说&quot;">​</a></h3><p>这章的关键，不是在制造玄虚，而是在提醒学习者：语言有用，但语言也有限。</p><p>人一旦开始命名，就会进入分别的世界：</p><ul><li>这是山</li><li>那是水</li><li>这是我</li><li>那是物</li></ul><p>这让世界变得可说、可分、可识别，但也容易让人把“名”误当成了实相本身。</p><p>因此，老子一开篇就先拆掉语言执着：</p><ul><li><code>无名</code> 让人更接近本始</li><li><code>有名</code> 让人看到万物如何展开</li></ul><p>这里并不是说“有名”错了，而是在说：如果只停在有名、有欲、有分别的层次，人就容易离源头越来越远。</p><p>“故常无欲，以观其妙；常有欲，以观其徼”也不是简单地赞美无欲、贬低有欲，而是在指出：不同的心态，会看到世界的不同层面。无欲更容易触到幽微之妙，有欲更容易看到外在之迹。</p><p>到了“此两者，同出而异名，同谓之玄”，老子又把前面展开的两端重新收拢：看似不同的无与有、妙与徼、源头与显现，其实同出一源。只是到了人的理解里，才被分成了不同名称。</p><p>所以“玄”并不是故作神秘，而是说：凡触及源头的问题，都深、都幽、都不是一句定义可以穷尽。</p><h3 id="用-这一章今天怎么用" tabindex="-1">用：这一章今天怎么用 <a class="header-anchor" href="#用-这一章今天怎么用" aria-label="Permalink to &quot;用：这一章今天怎么用&quot;">​</a></h3><p>这一章对今天的学习方式有直接提醒。</p><p>第一，不要急着为经典下死定义。<br> 第二，不要把语言当成终点。<br> 第三，不要把“无”和“有”学成彼此对立。<br> 第四，要学会两种观看方式并行：</p><ul><li>先以较少预设的心去感受其源头</li><li>再以结构化的方式整理其展开与层次</li></ul><p>如果把它放到今天的学习里，可以理解为：</p><ul><li><code>无名</code> 的看法，帮助我们保留开放、保留感受力</li><li><code>有名</code> 的看法，帮助我们建立概念、索引与结构</li></ul><p>两者都需要，缺一不可。</p><h2 id="【解读层】现代重述" tabindex="-1">【解读层】现代重述 <a class="header-anchor" href="#【解读层】现代重述" aria-label="Permalink to &quot;【解读层】现代重述&quot;">​</a></h2><p>能被完全说清的“道”，已经不是道本身；能被完全固定下来的“名”，也不是它最终的真实。</p><p>在没有命名之前，万物更接近它的本始；进入命名之后，世界开始展开成可分可识的万物。</p><p>当人放下执取与预设时，更容易看到那幽微深处的“妙”；当人带着分辨与认知去看时，更容易看到事物已经显现出来的边界、轮廓与端倪。</p><p>看似不同的“无”与“有”，其实来自同一个源头，只是名称不同、显现不同。真正的学习入口，不在抓住某个固定定义，而在愿意不断往更深处走。那道门，就是“众妙之门”。</p><h2 id="【解读层】我的理解" tabindex="-1">【解读层】我的理解 <a class="header-anchor" href="#【解读层】我的理解" aria-label="Permalink to &quot;【解读层】我的理解&quot;">​</a></h2><p>这一章让我最先感到的，不是抽象概念，而是一种强烈的源头感。</p><p>“无名天地之始”中的“天地之始”，让人自然感到宏大、广博，也让人意识到：这里谈的不是某个局部知识点，而是在追问万物未分之前的根。</p><p>我目前更愿意把这一章理解成：</p><ul><li><code>无名</code> 不是空无，而是未分、未定、未被概念切开的本始状态</li><li><code>有名</code> 不是错误，而是万物展开之后进入可分、可识、可说的层次</li><li><code>无欲</code> 与 <code>有欲</code> 不是价值上的绝对好坏，而是两种观看世界的方式</li></ul><p>所以真正重要的，不是站在哪一边，而是知道自己此刻是在看“源”，还是在看“流”；是在看“深处”，还是在看“轮廓”。</p><p>第一章像是在提醒学习者：不要把语言当终点，不要把名字当实相。先承认语言有边界，后面才真正进得去。</p><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>《道德经》通行本</li><li>王弼《老子注》相关系统</li></ul>',42))])}const y=c(g,[["render",x]]);export{D as __pageData,y as default};
